import { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [isLogin, setIsLogin] = useState(false);
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [courses, setCourses] = useState([]);
  const [enrolled, setEnrolled] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState(null);

  // LOGIN / REGISTER
  const handleAuth = async () => {
    const url = isRegister
      ? "http://localhost:5000/register"
      : "http://localhost:5000/login";

    await axios.post(url, { email, password });
    setIsLogin(true);
  };

  // LOAD DATA
  useEffect(() => {
    if (isLogin) {
      axios.get("http://localhost:5000/courses").then((res) => {
        setCourses(res.data);
      });

      axios.get("http://localhost:5000/enrolled").then((res) => {
        setEnrolled(res.data);
      });
    }
  }, [isLogin]);

  const handleEnroll = async (course) => {
    await axios.post("http://localhost:5000/enroll", { course });

    const res = await axios.get("http://localhost:5000/enrolled");
    setEnrolled(res.data);
  };

  // 🔐 AUTH UI
  if (!isLogin) {
    return (
      <div style={styles.authContainer}>
        <div style={styles.authBox}>
          <h2>{isRegister ? "Register" : "Login"}</h2>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) => setEmail(e.target.value)}
          />

          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <button style={styles.primaryBtn} onClick={handleAuth}>
            {isRegister ? "Register" : "Login"}
          </button>

          <p
            style={{ cursor: "pointer", marginTop: "10px" }}
            onClick={() => setIsRegister(!isRegister)}
          >
            {isRegister
              ? "Already have account? Login"
              : "New user? Register"}
          </p>
        </div>
      </div>
    );
  }

  // 🎥 VIDEO PAGE
  if (selectedCourse) {
    return (
      <div style={styles.videoPage}>
        <h2>{selectedCourse.title}</h2>

        <iframe
          width="900"
          height="500"
          src={selectedCourse.video}
          title="video"
          style={{ borderRadius: "10px" }}
        />

        <br /><br />

        <button
          style={styles.secondaryBtn}
          onClick={() => setSelectedCourse(null)}
        >
          ⬅ Back
        </button>
      </div>
    );
  }

  // 📊 DASHBOARD
  return (
    <div style={styles.app}>
      {/* SIDEBAR */}
      <div style={styles.sidebar}>
        <h2>🎓 LMS</h2>

        <h4>My Courses</h4>
        {enrolled.map((c) => (
          <div
            key={c.id}
            style={styles.sidebarItem}
            onClick={() => setSelectedCourse(c)}
          >
            {c.title}
          </div>
        ))}

        <button
          style={{ marginTop: "20px" }}
          onClick={() => setIsLogin(false)}
        >
          Logout
        </button>
      </div>

      {/* MAIN */}
      <div style={styles.content}>
        <h1>Explore Courses</h1>

        <div style={styles.grid}>
          {courses.map((course) => {
            const isEnrolled = enrolled.find(
              (c) => c.id === course.id
            );

            return (
              <div key={course.id} style={styles.card}>
                <img
                  src="https://source.unsplash.com/300x150/?programming"
                  alt="course"
                  style={styles.image}
                />

                <div style={{ padding: "15px" }}>
                  <h3>{course.title}</h3>
                  <p style={{ color: "gray" }}>{course.description}</p>

                  {!isEnrolled ? (
                    <button
                      style={styles.primaryBtn}
                      onClick={() => handleEnroll(course)}
                    >
                      Enroll Now
                    </button>
                  ) : (
                    <>
                      <button style={styles.successBtn}>
                        Enrolled ✅
                      </button>

                      <br /><br />

                      <button
                        style={styles.secondaryBtn}
                        onClick={() => setSelectedCourse(course)}
                      >
                        Watch Course 🎥
                      </button>
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// 🎨 STYLES
const styles = {
  authContainer: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    height: "100vh",
    background: "#f5f7fa",
  },
  authBox: {
    background: "white",
    padding: "30px",
    borderRadius: "10px",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
    textAlign: "center",
  },
  input: {
    display: "block",
    margin: "10px auto",
    padding: "10px",
    width: "250px",
  },
  app: {
    display: "flex",
    fontFamily: "Arial",
  },
  sidebar: {
    width: "250px",
    height: "100vh",
    background: "#111",
    color: "white",
    padding: "20px",
  },
  sidebarItem: {
    padding: "10px",
    marginTop: "10px",
    background: "#222",
    borderRadius: "5px",
    cursor: "pointer",
  },
  content: {
    flex: 1,
    padding: "30px",
    background: "#f5f7fa",
  },
  grid: {
    display: "flex",
    gap: "20px",
    flexWrap: "wrap",
  },
  card: {
    width: "280px",
    background: "white",
    borderRadius: "10px",
    overflow: "hidden",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },
  image: {
    width: "100%",
    height: "150px",
    objectFit: "cover",
  },
  primaryBtn: {
    background: "#007bff",
    color: "white",
    padding: "8px 15px",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
  secondaryBtn: {
    background: "#eee",
    padding: "8px 15px",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
  successBtn: {
    background: "green",
    color: "white",
    padding: "8px 15px",
    border: "none",
    borderRadius: "5px",
  },
  videoPage: {
    textAlign: "center",
    padding: "40px",
  },
};

export default App;
